import hashlib
from datetime import datetime
是否自动备份 = False #
是否启动韩文替换 = True #py文件保存的时候会自动替换韩文错误可自己扩展下面的韩文关键字
def 获取文件哈希(内容):
    """计算文件内容的哈希值"""
    return hashlib.md5(内容.encode('utf-8')).hexdigest()

def 备份源码文件(文件路径, 文件内容):
    
    if 是否自动备份 == False: return
    if 文件内容=="" or 文件内容 is None: return #忽略空文件
    """备份源码文件"""
    # 获取当前文件名和目录
    目录 = os.path.dirname(文件路径)
    文件名 = os.path.basename(文件路径)
    文件名_无扩展名, 扩展名 = os.path.splitext(文件名)
    if not 扩展名.endswith(".py"): return
    扩展名=".pybak"
    # 生成备份文件名（带时间戳）
    时间戳 = datetime.now().strftime("%Y%m%d_%H%M%S")
    备份文件名 = f"{文件名_无扩展名}-{时间戳}{扩展名}"
    备份文件路径 = os.path.join(目录, 备份文件名)
    
    # 查找最近的备份文件
    最新备份文件 = None
    最新备份时间 = None
    
    if os.path.exists(目录):
        for 文件 in os.listdir(目录):
            if 文件.startswith(f"{文件名_无扩展名}-") and 文件.endswith(扩展名):
                # 提取时间戳
                parts = 文件.split('-')
                if len(parts) >= 2:
                    try:
                        时间部分 = parts[-1].split('.')[0]  # 去掉扩展名
                        备份时间 = datetime.strptime(时间部分, "%Y%m%d_%H%M%S")
                        if 最新备份时间 is None or 备份时间 > 最新备份时间:
                            最新备份时间 = 备份时间
                            最新备份文件 = os.path.join(目录, 文件)
                    except ValueError:
                        continue
    
    # 检查最近备份文件内容是否相同
    需要备份 = True
    if 最新备份文件 and os.path.exists(最新备份文件):
        try:
            with open(最新备份文件, 'r', encoding='utf-8') as f:
                最新备份内容 = f.read()
                print(最新备份内容,file=sys.stderr)
             
                print(文件内容,file=sys.stderr)
            if  最新备份内容 == 文件内容:
                print("no change",file=sys.stderr)
                需要备份 = False
            else:
                print("change",file=sys.stderr)
                需要备份 = True
        except Exception as e:
            print("读取失败"+e,file=sys.stderr)
            pass  # 如果读取失败，则继续备份
    
    # 如果需要备份，则创建新备份
    if 需要备份:
        try:
            with open(备份文件路径, 'w', encoding='utf-8') as f:
                f.write(文件内容)
        except:
            pass  # 忽略备份错误

